{
  "family": "Houben-Hoesch Reaction/Synthesis",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "COc1cc(OC)cc(OC)c1"
    ],
    "product_smiles": [
      "CC(=O)c1cc(OC)cc(OC)c1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Zn]Cl",
      "Cl"
    ],
    "rationale": "This is a classic textbook example of the Houben-Hoesch reaction, featuring the acylation of a highly activated, electron-rich aromatic ring (1,3,5-trimethoxybenzene) with a simple nitrile (acetonitrile). The reaction is catalyzed by a Lewis acid (ZnCl2) and a protic acid (HCl), leading to the formation of an aryl ketone (2,4,6-trimethoxyacetophenone). The reactants and product are simple, acyclic where possible, and clearly illustrate the core transformation of this named reaction: electrophilic acylation of an activated arene using a nitrile.",
    "collision_avoidance_note": "This example avoids using phenol (which could trigger Fries rearrangement or Reimer-Tiemann queries) or benzene (which is too generic and could trigger Friedel-Crafts acylation queries). The use of a simple nitrile (acetonitrile) and a highly activated methoxy-substituted benzene ring is specific to the conditions often required for the Houben-Hoesch reaction, distinguishing it from other electrophilic aromatic substitution reactions."
  }
}
